spec.query:
from(bucket: "AI")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "domain_threats")
  |> filter(fn: (r) => r["_field"] == "vt_detections")
  |> group()
  |> reduce(
      fn: (r, accumulator) => ({
        Clean:    accumulator.Clean    + (if r["_value"] == 0                         then 1 else 0),
        Low:      accumulator.Low      + (if r["_value"] > 0  and r["_value"] <= 5  then 1 else 0),
        Medium:   accumulator.Medium   + (if r["_value"] > 5  and r["_value"] <= 15 then 1 else 0),
        High:     accumulator.High     + (if r["_value"] > 15 and r["_value"] <= 30 then 1 else 0),
        Critical: accumulator.Critical + (if r["_value"] > 30                        then 1 else 0)
      }),
      identity: {Clean: 0, Low: 0, Medium: 0, High: 0, Critical: 0}
    )
  |> drop(columns: ["_start", "_stop", "_time"])
